def process_article(article):
    title = article['title']
    content = article['content']
    has_video = article['has_video']

    # Replace Cluj names in title and content
    title = replace_cluj(title)
    content = replace_cluj(content)

    # Handle VIDEO/FOTO/AUDIO mentions sarcastically
    if has_video or 'VIDEO' in title.upper() or 'VIDEO' in content.upper():
